/** Computes the next generation of live cells per Conway's Game of Life rules. */
export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number): string => `${x},${y}`;
  const liveKeys = new Set(cells.map(([x, y]) => key(x, y)));
  const isAlive = (x: number, y: number): boolean => liveKeys.has(key(x, y));

  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;

  // Candidates: all live cells + all dead neighbors of live cells
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    candidates.set(key(x, y), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      candidates.set(key(nx, ny), [nx, ny]);
    }
  }

  const result: Cell[] = [];
  for (const [, cell] of candidates) {
    const [x, y] = cell;
    const n = countLiveNeighbors(x, y);
    if (isAlive(x, y) ? n === 2 || n === 3 : n === 3) {
      result.push(cell);
    }
  }
  return result;
}

